Функция ПолучитьСальдо(Счет) Экспорт
    Если НЕ ЗначениеЗаполнено(Счет) Тогда
        Возврат 0;
    КонецЕсли;

    Запрос = Новый Запрос;
    Запрос.Текст = 
    "ВЫБРАТЬ
    |   ЕСТЬNULL(СУММА(ХозрасчетныйОбороты.СуммаОборотДт), 0) КАК СуммаДт,
    |   ЕСТЬNULL(СУММА(ХозрасчетныйОбороты.СуммаОборотКт), 0) КАК СуммаКт
    |ИЗ
    |   РегистрБухгалтерии.Хозрасчетный.Обороты(, , , Счет В ИЕРАРХИИ (&Счет), , , , ) КАК ХозрасчетныйОбороты";

    Запрос.УстановитьПараметр("Счет", Счет);

    Результат = Запрос.Выполнить().Выбрать();
    Если Результат.Следующий() Тогда
        СуммаДт = Результат.СуммаДт;
        СуммаКт = Результат.СуммаКт;
    Иначе
        СуммаДт = 0;
        СуммаКт = 0;
    КонецЕсли;

    Если Счет.Вид = ВидСчета.Пассивный Тогда
        Возврат СуммаКт - СуммаДт;
    Иначе
        Возврат СуммаДт - СуммаКт;
    КонецЕсли;
КонецФункции
